1	//! Worker Registry for multi-router support
2	//!
3	//! Provides centralized registry for workers with model-based indexing
4	//!
5	//! # Performance Optimizations
6	//! The model index uses immutable Arc snapshots instead of RwLock for lock-free reads.
7	//! This is critical for high-concurrency scenarios where many requests query the same model.
8	//!
9	//! # Consistent Hash Ring
10	//! The registry maintains a pre-computed hash ring per model for O(log n) consistent hashing.
11	//! The ring is rebuilt only when workers are added/removed, not per-request.
12	//! Uses virtual nodes (150 per worker) for even distribution and blake3 for stable hashing.
13	
14	use std::sync::{Arc, RwLock};
15	
16	use dashmap::DashMap;
17	use smg_mesh::OptionalMeshSyncManager;
18	use uuid::Uuid;
19	
20	use crate::{
21	    core::{
22	        circuit_breaker::CircuitState,
23	        worker::{HealthChecker, RuntimeType, WorkerType},
24	        ConnectionMode, Worker,
25	    },
26	    observability::metrics::Metrics,
27	};
28	
29	/// Number of virtual nodes per physical worker for even distribution.
30	/// 150 is a common choice that provides good balance between memory and distribution.
31	const VIRTUAL_NODES_PER_WORKER: usize = 150;
32	
33	/// Consistent hash ring for O(log n) worker selection.
34	///
35	/// Each worker is placed at multiple positions (virtual nodes) on the ring
36	/// based on hash(worker_url + vnode_index). This provides:
37	/// - Even key distribution across workers
38	/// - Minimal key redistribution when workers are added/removed (~1/N keys move)
39	/// - O(log n) lookup via binary search
40	///
41	/// Uses blake3 for stable, fast hashing that's consistent across Rust versions.
42	#[derive(Debug, Clone)]
43	pub struct HashRing {
44	    /// Sorted list of (ring_position, worker_url)
45	    /// Multiple entries per worker (virtual nodes) for even distribution.
46	    /// Uses Arc<str> to share URL across all virtual nodes (150 refs vs 150 copies).
47	    entries: Arc<[(u64, Arc<str>)]>,
48	}
49	
50	impl HashRing {
51	    /// Build a hash ring from a list of workers.
52	    /// Creates VIRTUAL_NODES_PER_WORKER entries per worker for even distribution.
53	    pub fn new(workers: &[Arc<dyn Worker>]) -> Self {
54	        let mut entries: Vec<(u64, Arc<str>)> =
55	            Vec::with_capacity(workers.len() * VIRTUAL_NODES_PER_WORKER);
56	
57	        for worker in workers {
58	            // Create Arc<str> once per worker, share across all virtual nodes
59	            let url: Arc<str> = Arc::from(worker.url());
60	            let url_bytes = url.as_bytes();
61	
62	            // Create multiple virtual nodes per worker
63	            for vnode in 0..VIRTUAL_NODES_PER_WORKER {
64	                let mut hasher = blake3::Hasher::new();
65	                hasher.update(url_bytes);
66	                hasher.update(b"#");
67	                hasher.update(&(vnode as u64).to_le_bytes());
68	                let hash = hasher.finalize();
69	                let pos = u64::from_le_bytes(hash.as_bytes()[..8].try_into().unwrap());
70	                entries.push((pos, Arc::clone(&url)));
71	            }
72	        }
73	
74	        // Sort by ring position for binary search
75	        entries.sort_unstable_by_key(|(pos, _)| *pos);
76	
77	        Self {
78	            entries: Arc::from(entries.into_boxed_slice()),
79	        }
80	    }
81	
82	    /// Hash a string to a ring position using blake3 (stable across versions).
83	    #[inline]
84	    fn hash_position(s: &str) -> u64 {
85	        let hash = blake3::hash(s.as_bytes());
86	        // Take first 8 bytes as u64
87	        u64::from_le_bytes(hash.as_bytes()[..8].try_into().unwrap())
88	    }
89	
90	    /// Find worker URL for a key using consistent hashing.
91	    /// Returns the first healthy worker URL at or after the key's position (clockwise).
92	    ///
93	    /// - `key`: The routing key to hash
94	    /// - `is_healthy`: Function to check if a worker URL is healthy
95	    pub fn find_healthy_url<F>(&self, key: &str, is_healthy: F) -> Option<&str>
96	    where
97	        F: Fn(&str) -> bool,
98	    {
99	        if self.entries.is_empty() {
100	            return None;
101	        }
102	
103	        let key_pos = Self::hash_position(key);
104	
105	        // Binary search to find first entry at or after key_pos
106	        let start = self.entries.partition_point(|(pos, _)| *pos < key_pos);
107	
108	        // Walk clockwise from start, wrapping around
109	        // Track visited URLs to avoid checking same worker multiple times (virtual nodes)
110	        let mut checked_urls =
111	            std::collections::HashSet::with_capacity(self.worker_count().min(16));
112	
113	        for i in 0..self.entries.len() {
114	            let (_, url) = &self.entries[(start + i) % self.entries.len()];
115	            let url_str: &str = url;
116	
117	            // Skip if we already checked this worker (from another virtual node)
118	            if !checked_urls.insert(url_str) {
119	                continue;
120	            }
121	
122	            if is_healthy(url_str) {
123	                return Some(url_str);
124	            }
125	        }
126	
127	        None
128	    }
129	
130	    /// Check if the ring is empty
131	    pub fn is_empty(&self) -> bool {
132	        self.entries.is_empty()
133	    }
134	
135	    /// Get the number of entries in the ring (including virtual nodes)
136	    pub fn len(&self) -> usize {
137	        self.entries.len()
138	    }
139	
140	    /// Get the number of unique workers in the ring
141	    pub fn worker_count(&self) -> usize {
142	        self.entries.len() / VIRTUAL_NODES_PER_WORKER.max(1)
143	    }
144	}
