173	/// Model index using immutable snapshots for lock-free reads.
174	/// Each model maps to an Arc'd slice of workers that can be read without locking.
175	/// Updates create new snapshots (copy-on-write semantics).
176	type ModelIndex = Arc<DashMap<String, Arc<[Arc<dyn Worker>]>>>;
177	
178	/// Worker registry with model-based indexing
179	#[derive(Debug)]
180	pub struct WorkerRegistry {
181	    /// All workers indexed by ID
182	    workers: Arc<DashMap<WorkerId, Arc<dyn Worker>>>,
183	
184	    /// Model index for O(1) lookups using immutable snapshots.
185	    /// Uses Arc<[T]> instead of Arc<RwLock<Vec<T>>> for lock-free reads.
186	    model_index: ModelIndex,
187	
188	    /// Consistent hash rings per model for O(log n) routing.
189	    /// Rebuilt on worker add/remove (copy-on-write).
190	    hash_rings: Arc<DashMap<String, Arc<HashRing>>>,
191	
192	    /// Workers indexed by worker type
193	    type_workers: Arc<DashMap<WorkerType, Vec<WorkerId>>>,
194	
195	    /// Workers indexed by connection mode
196	    connection_workers: Arc<DashMap<ConnectionMode, Vec<WorkerId>>>,
197	
198	    /// URL to worker ID mapping
199	    url_to_id: Arc<DashMap<String, WorkerId>>,
200	    /// Optional mesh sync manager for state synchronization
201	    /// When None, the registry works independently without mesh synchronization
202	    /// Uses RwLock for thread-safe access when setting mesh_sync after initialization
203	    mesh_sync: Arc<RwLock<OptionalMeshSyncManager>>,
204	}
205	
206	impl WorkerRegistry {
207	    /// Create a new worker registry
208	    pub fn new() -> Self {
209	        Self {
210	            workers: Arc::new(DashMap::new()),
211	            model_index: Arc::new(DashMap::new()),
212	            hash_rings: Arc::new(DashMap::new()),
213	            type_workers: Arc::new(DashMap::new()),
214	            connection_workers: Arc::new(DashMap::new()),
215	            url_to_id: Arc::new(DashMap::new()),
216	            mesh_sync: Arc::new(RwLock::new(None)),
217	        }
218	    }
219	
220	    /// Rebuild the hash ring for a model based on current workers in the model index
221	    fn rebuild_hash_ring(&self, model_id: &str) {
222	        if let Some(workers) = self.model_index.get(model_id) {
223	            let ring = HashRing::new(&workers);
224	            self.hash_rings.insert(model_id.to_string(), Arc::new(ring));
225	        } else {
226	            // No workers for this model, remove the ring
227	            self.hash_rings.remove(model_id);
228	        }
229	    }
230	
231	    /// Get the hash ring for a model (O(1) lookup)
232	    pub fn get_hash_ring(&self, model_id: &str) -> Option<Arc<HashRing>> {
233	        self.hash_rings.get(model_id).map(|r| Arc::clone(&r))
234	    }
235	
236	    /// Set mesh sync manager (thread-safe, can be called after initialization)
237	    pub fn set_mesh_sync(&self, mesh_sync: OptionalMeshSyncManager) {
238	        *self.mesh_sync.write().unwrap() = mesh_sync;
239	    }
240	
241	    /// Register a new worker
242	    pub fn register(&self, worker: Arc<dyn Worker>) -> WorkerId {
243	        let worker_id = if let Some(existing_id) = self.url_to_id.get(worker.url()) {
244	            // Worker with this URL already exists, update it
245	            existing_id.clone()
246	        } else {
247	            WorkerId::new()
248	        };
249	
250	        // Store worker
251	        self.workers.insert(worker_id.clone(), worker.clone());
252	
253	        // Update URL mapping
254	        self.url_to_id
255	            .insert(worker.url().to_string(), worker_id.clone());
256	
257	        // Update model index for O(1) lookups using copy-on-write
258	        // This creates a new immutable snapshot with the added worker
259	        let model_id = worker.model_id().to_string();
260	        self.model_index
261	            .entry(model_id.clone())
262	            .and_modify(|existing| {
263	                // Create new snapshot with the additional worker
264	                let mut new_workers: Vec<Arc<dyn Worker>> = existing.iter().cloned().collect();
265	                new_workers.push(worker.clone());
266	                *existing = Arc::from(new_workers.into_boxed_slice());
267	            })
268	            .or_insert_with(|| Arc::from(vec![worker.clone()].into_boxed_slice()));
269	
270	        // Rebuild hash ring for this model
271	        self.rebuild_hash_ring(&model_id);
272	
273	        // Update type index (clone needed for DashMap key ownership)
274	        self.type_workers
275	            .entry(worker.worker_type().clone())
276	            .or_default()
277	            .push(worker_id.clone());
278	
279	        // Update connection mode index (clone needed for DashMap key ownership)
280	        self.connection_workers
281	            .entry(worker.connection_mode().clone())
282	            .or_default()
283	            .push(worker_id.clone());
284	
285	        // Sync to mesh if enabled (no-op if mesh is not enabled)
286	        if let Some(ref mesh_sync) = *self.mesh_sync.read().unwrap() {
287	            mesh_sync.sync_worker_state(
288	                worker_id.as_str().to_string(),
289	                worker.model_id().to_string(),
290	                worker.url().to_string(),
291	                worker.is_healthy(),
292	                0.0, // TODO: Get actual load
293	            );
294	        }
295	
296	        worker_id
297	    }
298	
299	    /// Reserve (or retrieve) a stable UUID for a worker URL.
300	    /// Uses atomic entry API to avoid race conditions between check and insert.
301	    pub fn reserve_id_for_url(&self, url: &str) -> WorkerId {
302	        self.url_to_id.entry(url.to_string()).or_default().clone()
303	    }
304	
305	    /// Best-effort lookup of the URL for a given worker ID.
306	    pub fn get_url_by_id(&self, worker_id: &WorkerId) -> Option<String> {
307	        if let Some(worker) = self.get(worker_id) {
308	            return Some(worker.url().to_string());
309	        }
310	        self.url_to_id
311	            .iter()
312	            .find_map(|entry| (entry.value() == worker_id).then(|| entry.key().clone()))
313	    }
314	
315	    /// Remove a worker by ID
316	    pub fn remove(&self, worker_id: &WorkerId) -> Option<Arc<dyn Worker>> {
317	        if let Some((_, worker)) = self.workers.remove(worker_id) {
318	            // Remove from URL mapping
319	            self.url_to_id.remove(worker.url());
320	
321	            // Remove from model index using copy-on-write
322	            // Create new snapshot without the removed worker
323	            let worker_url = worker.url();
324	            let model_id = worker.model_id().to_string();
325	            if let Some(mut entry) = self.model_index.get_mut(&model_id) {
326	                let new_workers: Vec<Arc<dyn Worker>> = entry
327	                    .iter()
328	                    .filter(|w| w.url() != worker_url)
329	                    .cloned()
330	                    .collect();
331	                *entry = Arc::from(new_workers.into_boxed_slice());
332	            }
333	
334	            // Rebuild hash ring for this model
335	            self.rebuild_hash_ring(&model_id);
336	
337	            // Remove from type index
338	            if let Some(mut type_workers) = self.type_workers.get_mut(worker.worker_type()) {
339	                type_workers.retain(|id| id != worker_id);
340	            }
341	
342	            // Remove from connection mode index
343	            if let Some(mut conn_workers) =
344	                self.connection_workers.get_mut(worker.connection_mode())
345	            {
346	                conn_workers.retain(|id| id != worker_id);
347	            }
348	
349	            worker.set_healthy(false);
350	            Metrics::remove_worker_metrics(worker.url());
351	
352	            // Sync removal to mesh if enabled (no-op if mesh is not enabled)
353	            if let Some(ref mesh_sync) = *self.mesh_sync.read().unwrap() {
354	                mesh_sync.remove_worker_state(worker_id.as_str());
355	            }
356	
357	            Some(worker)
358	        } else {
359	            None
360	        }
361	    }
362	
363	    /// Remove a worker by URL
364	    pub fn remove_by_url(&self, url: &str) -> Option<Arc<dyn Worker>> {
365	        if let Some((_, worker_id)) = self.url_to_id.remove(url) {
366	            self.remove(&worker_id)
367	        } else {
368	            None
369	        }
370	    }
371	
372	    /// Get a worker by ID
373	    pub fn get(&self, worker_id: &WorkerId) -> Option<Arc<dyn Worker>> {
374	        self.workers.get(worker_id).map(|entry| entry.clone())
375	    }
376	
377	    /// Get a worker by URL
378	    pub fn get_by_url(&self, url: &str) -> Option<Arc<dyn Worker>> {
379	        self.url_to_id.get(url).and_then(|id| self.get(&id))
380	    }
381	
382	    /// Empty worker slice constant for returning when no workers found
383	    const EMPTY_WORKERS: &'static [Arc<dyn Worker>] = &[];
384	
385	    /// Get all workers for a model (O(1) optimized, lock-free)
386	    /// Returns an Arc to the immutable worker slice - just an atomic refcount bump.
387	    /// This is the fastest possible read path with zero contention.
388	    pub fn get_by_model(&self, model_id: &str) -> Arc<[Arc<dyn Worker>]> {
389	        self.model_index
390	            .get(model_id)
391	            .map(|workers| Arc::clone(&workers))
392	            .unwrap_or_else(|| Arc::from(Self::EMPTY_WORKERS))
393	    }
