395	    /// Get all workers by worker type
396	    pub fn get_by_type(&self, worker_type: &WorkerType) -> Vec<Arc<dyn Worker>> {
397	        self.type_workers
398	            .get(worker_type)
399	            .map(|ids| ids.iter().filter_map(|id| self.get(id)).collect())
400	            .unwrap_or_default()
401	    }
