404	    pub fn update_worker_health(&self, worker_id: &WorkerId, is_healthy: bool) {
405	        if let Some(worker) = self.workers.get(worker_id) {
406	            // Update worker health (if Worker trait has a method for this)
407	            // For now, we'll just sync to mesh
408	
409	            // Sync to mesh if enabled (no-op if mesh is not enabled)
410	            if let Some(ref mesh_sync) = *self.mesh_sync.read().unwrap() {
411	                mesh_sync.sync_worker_state(
412	                    worker_id.as_str().to_string(),
413	                    worker.model_id().to_string(),
414	                    worker.url().to_string(),
415	                    is_healthy,
416	                    0.0, // TODO: Get actual load
417	                );
418	            }
419	        }
420	    }
