422	    /// Get all prefill workers (regardless of bootstrap_port)
423	    pub fn get_prefill_workers(&self) -> Vec<Arc<dyn Worker>> {
424	        self.workers
425	            .iter()
426	            .filter_map(|entry| {
427	                let worker = entry.value();
428	                match worker.worker_type() {
429	                    WorkerType::Prefill { .. } => Some(worker.clone()),
430	                    _ => None,
431	                }
432	            })
433	            .collect()
434	    }
