504	    /// Get workers filtered by multiple criteria
505	    ///
506	    /// This method allows flexible filtering of workers based on:
507	    /// - model_id: Filter by specific model
508	    /// - worker_type: Filter by worker type (Regular, Prefill, Decode)
509	    /// - connection_mode: Filter by connection mode (Http, Grpc)
510	    /// - runtime_type: Filter by runtime type (Sglang, Vllm, External)
511	    /// - healthy_only: Only return healthy workers
512	    pub fn get_workers_filtered(
513	        &self,
514	        model_id: Option<&str>,
515	        worker_type: Option<WorkerType>,
516	        connection_mode: Option<ConnectionMode>,
517	        runtime_type: Option<RuntimeType>,
518	        healthy_only: bool,
519	    ) -> Vec<Arc<dyn Worker>> {
520	        // Start with the most efficient collection based on filters
521	        // Use model index when possible as it's O(1) lookup
522	        let workers: Vec<Arc<dyn Worker>> = if let Some(model) = model_id {
523	            self.get_by_model(model).to_vec()
524	        } else {
525	            self.get_all()
526	        };
527	
528	        // Apply remaining filters
529	        workers
530	            .into_iter()
531	            .filter(|w| {
532	                // Check worker_type if specified
533	                if let Some(ref wtype) = worker_type {
534	                    if *w.worker_type() != *wtype {
535	                        return false;
536	                    }
537	                }
538	
539	                // Check connection_mode if specified (using matches for flexible gRPC matching)
540	                if let Some(ref conn) = connection_mode {
541	                    if !w.connection_mode().matches(conn) {
542	                        return false;
543	                    }
544	                }
545	
546	                // Check runtime_type if specified
547	                if let Some(ref rt) = runtime_type {
548	                    if w.metadata().runtime_type != *rt {
549	                        return false;
550	                    }
551	                }
552	
553	                // Check health if required
554	                if healthy_only && !w.is_healthy() {
555	                    return false;
556	                }
557	
558	                true
559	            })
560	            .collect()
561	    }
