563	    /// Get worker statistics (lock-free)
564	    pub fn stats(&self) -> WorkerRegistryStats {
565	        let total_workers = self.workers.len();
566	        // Count models directly instead of allocating Vec via get_models() (lock-free)
567	        let total_models = self
568	            .model_index
569	            .iter()
570	            .filter(|entry| !entry.value().is_empty())
571	            .count();
572	
573	        let mut healthy_count = 0;
574	        let mut total_load = 0;
575	        let mut regular_count = 0;
576	        let mut prefill_count = 0;
577	        let mut decode_count = 0;
578	        let mut http_count = 0;
579	        let mut grpc_count = 0;
580	        let mut cb_open_count = 0;
581	        let mut cb_half_open_count = 0;
582	
583	        // Iterate DashMap directly to avoid cloning all workers via get_all()
584	        for entry in self.workers.iter() {
585	            let worker = entry.value();
586	            if worker.is_healthy() {
587	                healthy_count += 1;
588	            }
589	            total_load += worker.load();
590	
591	            match worker.worker_type() {
592	                WorkerType::Regular => regular_count += 1,
593	                WorkerType::Prefill { .. } => prefill_count += 1,
594	                WorkerType::Decode => decode_count += 1,
595	            }
596	
597	            match worker.connection_mode() {
598	                ConnectionMode::Http => http_count += 1,
599	                ConnectionMode::Grpc { .. } => grpc_count += 1,
600	            }
601	
602	            match worker.circuit_breaker().state() {
603	                CircuitState::Open => cb_open_count += 1,
604	                CircuitState::HalfOpen => cb_half_open_count += 1,
605	                CircuitState::Closed => {}
606	            }
607	        }
608	
609	        WorkerRegistryStats {
610	            total_workers,
611	            total_models,
612	            healthy_workers: healthy_count,
613	            unhealthy_workers: total_workers.saturating_sub(healthy_count),
614	            total_load,
615	            regular_workers: regular_count,
616	            prefill_workers: prefill_count,
617	            decode_workers: decode_count,
618	            http_workers: http_count,
619	            grpc_workers: grpc_count,
620	            circuit_breaker_open: cb_open_count,
621	            circuit_breaker_half_open: cb_half_open_count,
622	        }
623	    }
624	
625	    /// Get counts of regular and PD workers efficiently (O(1))
626	    /// This avoids the overhead of get_all() which allocates memory and iterates all workers
627	    pub fn get_worker_distribution(&self) -> (usize, usize) {
628	        // Use the existing type_workers index for O(1) lookup
629	        let regular_count = self
630	            .type_workers
631	            .get(&WorkerType::Regular)
632	            .map(|v| v.len())
633	            .unwrap_or(0);
634	
635	        // Get total workers count efficiently from DashMap
636	        let total_workers = self.workers.len();
637	
638	        // PD workers are any workers that are not Regular
639	        let pd_count = total_workers.saturating_sub(regular_count);
640	
641	        (regular_count, pd_count)
642	    }
643	
644	    /// Start a health checker for all workers in the registry
645	    /// This should be called once after the registry is populated with workers
646	    pub(crate) fn start_health_checker(&self, check_interval_secs: u64) -> HealthChecker {
647	        use std::sync::{
648	            atomic::{AtomicBool, Ordering},
649	            Arc,
650	        };
651	
652	        let shutdown = Arc::new(AtomicBool::new(false));
653	        let shutdown_clone = shutdown.clone();
654	        let workers_ref = self.workers.clone();
655	
656	        let handle = tokio::spawn(async move {
657	            let mut interval =
658	                tokio::time::interval(tokio::time::Duration::from_secs(check_interval_secs));
659	
660	            loop {
661	                interval.tick().await;
662	
663	                // Check for shutdown signal
664	                if shutdown_clone.load(Ordering::Acquire) {
665	                    tracing::debug!("Registry health checker shutting down");
666	                    break;
667	                }
668	
669	                // Get all workers from registry
670	                let workers: Vec<Arc<dyn Worker>> = workers_ref
671	                    .iter()
672	                    .map(|entry| entry.value().clone())
673	                    .collect();
674	
675	                // Perform health checks in parallel for better performance
676	                // This is especially important when there are many workers
677	                let health_futures: Vec<_> = workers
678	                    .iter()
679	                    .filter(|worker| !worker.metadata().health_config.disable_health_check)
680	                    .map(|worker| {
681	                        let worker = worker.clone();
682	                        async move {
683	                            let _ = worker.check_health_async().await;
684	                        }
685	                    })
686	                    .collect();
687	                futures::future::join_all(health_futures).await;
688	            }
689	        });
690	
691	        HealthChecker::new(handle, shutdown)
692	    }
693	}
694	
695	impl Default for WorkerRegistry {
696	    fn default() -> Self {
697	        Self::new()
698	    }
699	}
