438	impl ConnectionMode {
439	    /// Check if this connection mode matches another, with special handling for gRPC
440	    /// This allows matching any gRPC connection regardless of port when comparing
441	    /// Grpc { port: None } as a wildcard
442	    pub fn matches(&self, filter: &ConnectionMode) -> bool {
443	        match (self, filter) {
444	            (ConnectionMode::Http, ConnectionMode::Http) => true,
445	            (ConnectionMode::Grpc { .. }, ConnectionMode::Grpc { port: None }) => true,
446	            (ConnectionMode::Grpc { port: p1 }, ConnectionMode::Grpc { port: p2 }) => p1 == p2,
447	            _ => false,
448	        }
449	    }
