706	#[async_trait]
707	impl Worker for BasicWorker {
708	    fn url(&self) -> &str {
709	        &self.metadata.url
710	    }
711	
712	    fn api_key(&self) -> &Option<String> {
713	        &self.metadata.api_key
714	    }
715	
716	    fn worker_type(&self) -> &WorkerType {
717	        &self.metadata.worker_type
718	    }
719	
720	    fn connection_mode(&self) -> &ConnectionMode {
721	        &self.metadata.connection_mode
722	    }
723	
724	    fn is_healthy(&self) -> bool {
725	        self.healthy.load(Ordering::Acquire)
726	    }
727	
728	    fn set_healthy(&self, healthy: bool) {
729	        self.healthy.store(healthy, Ordering::Release);
730	        Metrics::set_worker_health(self.url(), healthy);
731	    }
732	
733	    async fn check_health_async(&self) -> WorkerResult<()> {
734	        if self.metadata.health_config.disable_health_check {
735	            if !self.is_healthy() {
736	                self.set_healthy(true);
737	            }
738	            return Ok(());
739	        }
740	
741	        let health_result = match &self.metadata.connection_mode {
742	            ConnectionMode::Http => self.http_health_check().await?,
743	            ConnectionMode::Grpc { .. } => self.grpc_health_check().await?,
744	        };
745	
746	        // Get worker type label for metrics
747	        let worker_type_str = self.metadata.worker_type.as_metric_label();
748	
749	        if health_result {
750	            self.consecutive_failures.store(0, Ordering::Release);
751	            let successes = self.consecutive_successes.fetch_add(1, Ordering::AcqRel) + 1;
752	
753	            // Record health check success metric
754	            Metrics::record_worker_health_check(worker_type_str, metrics_labels::CB_SUCCESS);
755	
756	            if !self.is_healthy()
757	                && successes >= self.metadata.health_config.success_threshold as usize
758	            {
759	                self.set_healthy(true);
760	                self.consecutive_successes.store(0, Ordering::Release);
761	            }
762	            Ok(())
763	        } else {
764	            self.consecutive_successes.store(0, Ordering::Release);
765	            let failures = self.consecutive_failures.fetch_add(1, Ordering::AcqRel) + 1;
766	
767	            // Record health check failure metric
768	            Metrics::record_worker_health_check(worker_type_str, metrics_labels::CB_FAILURE);
769	
770	            if self.is_healthy()
771	                && failures >= self.metadata.health_config.failure_threshold as usize
772	            {
773	                self.set_healthy(false);
774	                self.consecutive_failures.store(0, Ordering::Release);
775	            }
776	
777	            Err(WorkerError::HealthCheckFailed {
778	                url: self.metadata.url.clone(),
779	                reason: format!("Health check failed (consecutive failures: {})", failures),
780	            })
781	        }
782	    }
783	
784	    fn load(&self) -> usize {
785	        self.load_counter.load(Ordering::Relaxed)
786	    }
787	
788	    fn increment_load(&self) {
789	        self.load_counter.fetch_add(1, Ordering::Relaxed);
790	        self.update_running_requests_metrics();
791	    }
792	
793	    fn decrement_load(&self) {
794	        if self
795	            .load_counter
796	            .fetch_update(Ordering::Relaxed, Ordering::Relaxed, |current| {
797	                current.checked_sub(1)
798	            })
799	            .is_err()
800	        {
801	            tracing::warn!(
802	                worker_url = %self.metadata.url,
803	                "Attempted to decrement load counter that is already at 0"
804	            );
805	        }
806	        self.update_running_requests_metrics();
807	    }
808	
809	    fn reset_load(&self) {
810	        self.load_counter.store(0, Ordering::Relaxed);
811	        self.update_running_requests_metrics();
812	    }
813	
814	    fn worker_routing_key_load(&self) -> &WorkerRoutingKeyLoad {
815	        &self.worker_routing_key_load
816	    }
817	
818	    fn processed_requests(&self) -> usize {
819	        self.processed_counter.load(Ordering::Relaxed)
820	    }
821	
822	    fn increment_processed(&self) {
823	        self.processed_counter.fetch_add(1, Ordering::Relaxed);
824	    }
