1141	/// RAII guard for worker load management
1142	///
1143	/// Automatically decrements worker load when dropped. Can be attached to
1144	/// an axum Response to tie the guard's lifetime to the response body,
1145	/// which is essential for streaming responses where the function returns
1146	/// immediately but the stream continues in the background.
1147	pub struct WorkerLoadGuard {
1148	    worker: Arc<dyn Worker>,
1149	    routing_key: Option<String>,
1150	}
1151	
1152	impl WorkerLoadGuard {
1153	    pub fn new(worker: Arc<dyn Worker>, headers: Option<&http::HeaderMap>) -> Self {
1154	        use crate::routers::header_utils::extract_routing_key;
1155	
1156	        worker.increment_load();
1157	
1158	        let routing_key = extract_routing_key(headers).map(String::from);
1159	
1160	        if let Some(ref key) = routing_key {
1161	            worker.worker_routing_key_load().increment(key);
1162	        }
1163	
1164	        Self {
1165	            worker,
1166	            routing_key,
1167	        }
1168	    }
1169	}
1170	
1171	impl Drop for WorkerLoadGuard {
1172	    fn drop(&mut self) {
1173	        self.worker.decrement_load();
1174	        if let Some(ref key) = self.routing_key {
1175	            self.worker.worker_routing_key_load().decrement(key);
1176	        }
1177	    }
1178	}
