1259	/// Helper to convert Worker trait object to WorkerInfo struct
1260	pub fn worker_to_info(worker: &Arc<dyn Worker>) -> WorkerInfo {
1261	    // Cache references that are used multiple times to avoid redundant method calls
1262	    let worker_type = worker.worker_type();
1263	    let connection_mode = worker.connection_mode();
1264	    let url = worker.url();
1265	    let model_id = worker.model_id();
1266	
1267	    let worker_type_str = match worker_type {
1268	        WorkerType::Regular => "regular",
1269	        WorkerType::Prefill { .. } => "prefill",
1270	        WorkerType::Decode => "decode",
1271	    };
1272	
1273	    let bootstrap_port = match worker_type {
1274	        WorkerType::Prefill { bootstrap_port } => *bootstrap_port,
1275	        _ => None,
1276	    };
1277	
1278	    let runtime_type = match connection_mode {
1279	        ConnectionMode::Grpc { .. } => Some(worker.metadata().runtime_type.to_string()),
1280	        ConnectionMode::Http => None,
1281	    };
1282	
1283	    WorkerInfo {
1284	        id: url.to_string(),
1285	        url: url.to_string(),
1286	        model_id: model_id.to_string(),
1287	        priority: worker.priority(),
1288	        cost: worker.cost(),
1289	        worker_type: worker_type_str.to_string(),
1290	        is_healthy: worker.is_healthy(),
1291	        load: worker.load(),
1292	        connection_mode: connection_mode.to_string(),
1293	        runtime_type,
1294	        tokenizer_path: worker.tokenizer_path(model_id).map(String::from),
1295	        reasoning_parser: worker.reasoning_parser(model_id).map(String::from),
1296	        tool_parser: worker.tool_parser(model_id).map(String::from),
1297	        chat_template: worker.chat_template(model_id).map(String::from),
1298	        bootstrap_port,
1299	        metadata: worker.metadata().labels.clone(),
1300	        disable_health_check: worker.metadata().health_config.disable_health_check,
1301	        job_status: None,
1302	    }
1303	}
